#define MY_OBSERVERSERVICE_CONTRACTID "@mozilla.org/my-observer-service;1"

class MyObserverService final : public nsIObserverService {
 public:
  MyObserverService();

  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVERSERVICE

 private:
  ~MyObserverService();

  bool mShuttingDown;
  nsTHashtable<nsObserverList> mObserverTopicTable;
};

#endif /* MyObserverService_h_ */

